from typing import List
from collections import defaultdict

class Solution:
    def getClassMonitor(self, names: List[str], ballotTickets: List[str]) -> str:
        n = len(names)

        # 原始总票数超过 3N，直接无效
        if len(ballotTickets) > 3 * n:
            return "Invalid election."

        # special 用来表示该写法存在歧义，不能唯一匹配
        special = "#INVALID#"
        mapping = {}

        # 预处理每个名字的所有合法连续段写法
        for name in names:
            parts = name.split('-')
            m = len(parts)
            for i in range(m):
                cur = []
                for j in range(i, m):
                    cur.append(parts[j])
                    key = "-".join(cur)
                    # 记录写法映射关系
                    if key not in mapping:
                        mapping[key] = name
                    elif mapping[key] != name:
                        mapping[key] = special

        # 统计有效票
        cnt = defaultdict(int)
        valid_votes = 0

        for ticket in ballotTickets:
            # 若票对应到唯一学生，计票 +1
            if ticket in mapping and mapping[ticket] != special:
                person = mapping[ticket]
                cnt[person] += 1
                valid_votes += 1

        # 没有任何有效票，则选举无效
        if valid_votes == 0:
            return "Invalid election."

        # 某位同学得票数超过班级总人数，则无效
        for v in cnt.values():
            if v > n:
                return "Invalid election."

        # 选出票数最多；若并列，选字典序更小者
        ans = ""
        max_vote = -1
        for name in cnt:
            if cnt[name] > max_vote or (cnt[name] == max_vote and name < ans):
                max_vote = cnt[name]
                ans = name

        return ans
