```java
import java.util.*;

public class Solution {
    /**
     * 班长选举：根据名字与选票映射关系确定当选人
     */
    public String getClassMonitor (ArrayList<String> names, ArrayList<String> ballotTickets) {
        int n = names.size();

        // 原始总票数超过 3N，直接无效
        if (ballotTickets.size() > 3 * n) {
            return "Invalid election.";
        }

        // special 标记：该写法有歧义
        String special = "#INVALID#";
        Map<String, String> mapping = new HashMap<>();

        // 预处理每个名字的所有合法连续段写法
        for (String name : names) {
            String[] parts = name.split("-");
            int m = parts.length;

            for (int i = 0; i < m; i++) {
                StringBuilder sb = new StringBuilder();
                for (int j = i; j < m; j++) {
                    if (j > i) sb.append("-");
                    sb.append(parts[j]);
                    String key = sb.toString();

                    if (!mapping.containsKey(key)) {
                        mapping.put(key, name);
                    } else if (!mapping.get(key).equals(name)) {
                        mapping.put(key, special);
                    }
                }
            }
        }

        // 统计有效票数
        Map<String, Integer> cnt = new HashMap<>();
        int validVotes = 0;

        for (String ticket : ballotTickets) {
            if (mapping.containsKey(ticket) && !mapping.get(ticket).equals(special)) {
                String person = mapping.get(ticket);
                cnt.put(person, cnt.getOrDefault(person, 0) + 1);
                validVotes++;
            }
        }

        // 没有任何有效票，则选举无效
        if (validVotes == 0) return "Invalid election.";

        // 某位同学得票数超过班级总人数，则无效
        for (int v : cnt.values()) {
            if (v > n) return "Invalid election.";
        }

        // 选出票数最多者；若票数相同，取字典序更小者
        String ans = "";
        int maxVote = -1;

        for (String name : cnt.keySet()) {
            int vote = cnt.get(name);
            if (vote > maxVote || (vote == maxVote && name.compareTo(ans) < 0)) {
                maxVote = vote;
                ans = name;
            }
        }

        return ans;
    }
}
