var getClassMonitor = function(names, ballotTickets) {
    const N = names.length;
    if (ballotTickets.length > 3 * N) return "Invalid election.";

    const mapping = new Map();
    // 预处理所有合法连续段写法
    for (const name of names) {
        const parts = name.split('-');
        const m = parts.length;
        for (let i = 0; i < m; i++) {
            for (let j = i; j < m; j++) {
                const key = parts.slice(i, j + 1).join('-');
                if (!mapping.has(key)) mapping.set(key, name);
                else if (mapping.get(key) !== name) mapping.set(key, '#INVALID#');
            }
        }
    }

    const votes = new Map();
    let validVotes = 0;
    for (const ticket of ballotTickets) {
        const match = mapping.get(ticket);
        if (match && match !== '#INVALID#') {
            votes.set(match, (votes.get(match) || 0) + 1);
            validVotes++;
        }
    }

    if (validVotes === 0) return "Invalid election.";
    for (const v of votes.values()) if (v > N) return "Invalid election.";

    let best = null, maxVotes = -1;
    for (const [name, cnt] of votes) {
        if (cnt > maxVotes || (cnt === maxVotes && name < best)) {
            maxVotes = cnt;
            best = name;
        }
    }
    return best;
};
