#include <stdlib.h>
#include <string.h>

// 判断票据是否为该学生名字的连续段
static int _isMatch(const char* name, const char* ticket) {
    int nLen = (int)strlen(name), tLen = (int)strlen(ticket);
    if (tLen > nLen) return 0;
    // 添加分隔符辅助匹配
    char* nw = (char*)malloc(nLen + 3);
    char* tw = (char*)malloc(tLen + 3);
    nw[0] = '-'; memcpy(nw + 1, name, nLen); nw[nLen + 1] = '-'; nw[nLen + 2] = '\0';
    tw[0] = '-'; memcpy(tw + 1, ticket, tLen); tw[tLen + 1] = '-'; tw[tLen + 2] = '\0';
    int ret = strstr(nw, tw) != NULL;
    free(nw); free(tw);
    return ret;
}

char* getClassMonitor(char** names, int namesSize, char** ballotTickets, int ballotTicketsSize) {
    int N = namesSize, M = ballotTicketsSize;
    if (M > 3 * N) return "Invalid election.";

    int* votes = (int*)calloc(N, sizeof(int));
    for (int b = 0; b < M; b++) {
        int matchIdx = -1;
        for (int i = 0; i < N; i++) {
            if (_isMatch(names[i], ballotTickets[b])) {
                if (matchIdx == -1) matchIdx = i;
                else { matchIdx = -2; break; } // 多人匹配则无效
            }
        }
        if (matchIdx >= 0) votes[matchIdx]++;
    }

    int totalValid = 0;
    char* best = NULL;
    int bestVotes = 0;
    for (int i = 0; i < N; i++) {
        totalValid += votes[i];
        if (votes[i] > N) { free(votes); return "Invalid election."; }
        if (votes[i] > bestVotes) { bestVotes = votes[i]; best = names[i]; }
        else if (votes[i] == bestVotes && bestVotes > 0 && strcmp(names[i], best) < 0) best = names[i];
    }
    free(votes);
    if (totalValid == 0 || bestVotes == 0) return "Invalid election.";
    return best;
}
